// src/pages/Home.jsx  (or src/components/Home.jsx)
import React from 'react';
import { Link } from 'react-router-dom';
import img1 from './images/download.jpeg';
import img2 from './images/images.jpeg';
import img3 from './images/photo-1437482078695-73f5ca6c96e2.avif';
import './Home.css'; // We'll add styles below

const Home = () => {
  return (
    <div className="home-page">
      {/* Hero Section */}
      <div className='Navbar'>

      </div>


      <div className=''>
        <div id="carouselExampleIndicators" className="carousel slide" data-ride="carousel">
          <ol className="carousel-indicators">
            <li data-target="#carouselExampleIndicators" data-slide-to="0" className="active"></li>
            <li data-target="#carouselExampleIndicators" data-slide-to="1"></li>
            <li data-target="#carouselExampleIndicators" data-slide-to="2"></li>
          </ol>
          <div className="carousel-inner">
            <div className="carousel-item active">
              <img className="d-block w-" src={img1} alt="Colorful Fish" />
            </div>
            <div className="carousel-item">
              <img className="d-block w-100" src={img2} alt="Tropical Aquarium" />
            </div>
            <div className="carousel-item">
              <img className="d-block w-100" src={img3} alt="Marine Life" />
            </div>
          </div>
          <a className="carousel-control-prev" href="#carouselExampleIndicators" role="button" data-slide="prev">
            <span className="carousel-control-prev-icon" aria-hidden="true"></span>
            <span className="sr-only">Previous</span>
          </a>
          <a className="carousel-control-next" href="#carouselExampleIndicators" role="button" data-slide="next">
            <span className="carousel-control-next-icon" aria-hidden="true"></span>
            <span className="sr-only">Next</span>
          </a>
        </div>
      </div>
    </div>
  );
};

export default Home;
